13	const BASE_PREMIUMS: Record<string, number> = {
14	  sword: 100,
15	  amulet: 60,
16	  staff: 80,
17	  potion: 40,
18	  rune: 25,
19	  moonstone: 25,
20	};
21	
22	const PROCESSING_FEE = 5;
23	const FIRST_INSURANCE_RATE = 0.1;
24	const CURSED_SURCHARGE_RATE = 0.5;
25	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
26	const HIGH_ENCHANTMENT_THRESHOLD = 5;
27	
28	const COMPONENT_BLOCK_SIZE = 3;
29	const COMPONENT_BLOCK_PREMIUM = 60;
30	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
31	
32	const componentPremium = (type: string, count: number): number =>
33	  count === COMPONENT_BLOCK_SIZE
34	    ? COMPONENT_BLOCK_PREMIUM
35	    : count * BASE_PREMIUMS[type];
36	
37	const itemSurcharge = (item: Item, basePremium: number): number =>
38	  (item.cursed ? basePremium * CURSED_SURCHARGE_RATE : 0) +
39	  (item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD ? basePremium * HIGH_ENCHANTMENT_SURCHARGE_RATE : 0);
40	
41	export function quote(customer: Customer, items: Item[]): number {
42	  if (items.length === 0) return PROCESSING_FEE;
43	
44	  let basePremium = 0;
45	  let totalItemSurcharges = 0;
46	  const componentCounts: Record<string, number> = {};
47	
48	  for (const item of items) {
49	    if (COMPONENT_TYPES.has(item.type)) {
50	      componentCounts[item.type] = (componentCounts[item.type] || 0) + 1;
51	    } else {
52	      const itemBase = BASE_PREMIUMS[item.type];
53	      basePremium += itemBase;
54	      totalItemSurcharges += itemSurcharge(item, itemBase);
55	    }
56	  }
57	
58	  for (const type of Object.keys(componentCounts)) {
59	    basePremium += componentPremium(type, componentCounts[type]);
60	  }
61	
62	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_RATE;
63	  return Math.ceil(basePremium + totalItemSurcharges + firstInsuranceSurcharge + PROCESSING_FEE);
64	}
